import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Base premium calculations - quote operation
  it.todo("quote with empty item list returns premium of 5 (just processing fee)");
  it.todo("quote with a single plain sword returns base premium + fee");
  it.todo("quote with a single plain amulet returns base premium + fee");
  it.todo("quote with a single plain staff returns base premium + fee");
  it.todo("quote with a single plain potion returns base premium + fee");

  // Components
  it.todo("quote with 2 runes returns 50G base + fee (no block)");
  it.todo("quote with 3 runes returns 60G base + fee (block applies)");
  it.todo("quote with 4 runes returns 100G base + fee (no block)");
  it.todo("quote with 7 runes returns 175G base + fee");
  it.todo("quote with 2 runes + 1 moonstone returns 75G base + fee (no block, different types)");
  it.todo("quote with 3 runes + 3 moonstones returns 120G base + fee (two separate blocks)");

  // Item-specific modifiers
  it.todo("quote with a cursed sword adds 50% surcharge to sword base premium");
  it.todo("quote with a sword enchantment 5 adds 30% high-enchantment surcharge");
  it.todo("quote with a sword enchantment 4 does not add high-enchantment surcharge");
  it.todo("quote with a cursed sword enchantment 5 adds both surcharges");

  // Policy-wide modifiers
  it.todo("quote for customer with 2 years gets 20% loyalty discount on policy base");
  it.todo("quote applies 10% first insurance surcharge on policy base");
  it.todo("quote for customer's second contract applies 15% follow-up discount");

  // Multi-item policies - modifier scope
  it.todo("quote with cursed sword + plain amulet applies cursed surcharge only to sword");

  // Rounding
  it.todo("quote rounds final premium up (in MHPCO's favor)");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, enchantment 3) -> premium 165");
  it.todo("long-standing customer's second contract with cursed sword enchantment 7 -> premium 160");

  // Claim processing - basic
  it.todo("claim with damage 500 on regular sword (no clauses) returns payout 400 (500 - 100 deductible)");
  it.todo("claim with damage 200 on a rune returns payout 100 (200 - 100 deductible)");

  // Claim - enchantment threshold
  it.todo("claim on enchantment 9 sword with damage 1000 returns payout 400 (50% then deductible)");

  // Claim - dragon material
  it.todo("claim on dragon-material sword damage 800 returns payout 700 (full then deductible)");

  // Claim - both clauses
  it.todo("claim on dragon-material enchantment 9 sword damage 1000 returns payout 400 (50% wins)");
  it.todo("claim on dragon-material enchantment 8 sword damage 1000 returns payout 400");

  // Claim - per-damage deductible
  it.todo("claim with two damaged items applies deductible per damage event");

  // Cap and remaining cap
  it.todo("claim returns remainingCap = cap - payout");
  it.todo("two successive claims exhaust the cap (1500/1500 on sword: 1400, then 600)");

  // CLI scenario with quote then claim
  it.todo("scenario with quote followed by claim returns results in order");
});

