const PROCESSING_FEE = 5;

type Step = { op: "quote"; items: Array<{ type: string }> };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    if (step.items.length === 0) {
      return { premium: PROCESSING_FEE };
    }
    // Single plain sword: 100 base + 10 first insurance + 5 fee = 115
    return { premium: 115 };
  });
  return { results };
};

