const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => {
    if (step.items.length === 0) {
      return { premium: PROCESSING_FEE };
    }
    const policyBase = step.items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
    const firstInsurance = policyBase * 0.1;
    return { premium: policyBase + firstInsurance + PROCESSING_FEE };
  });
  return { results };
};

