const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((sum, item) => sum + basePremiumOf(item), 0);

const componentGroupSubtotalOf = (group: Item[]): number =>
  group.length === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : sumBasePremiums(group);

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const existing = groups.get(item.type) ?? [];
    existing.push(item);
    groups.set(item.type, existing);
  }
  return groups;
};

const componentSubtotalOf = (components: Item[]): number =>
  [...groupByType(components).values()].reduce(
    (sum, group) => sum + componentGroupSubtotalOf(group),
    0,
  );

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const policyBaseOf = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((item) => !isComponent(item));
  return sumBasePremiums(mainItems) + componentSubtotalOf(components);
};

const firstInsuranceSurchargeOf = (policyBase: number): number =>
  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;

const cursedSurchargeOf = (item: Item): number =>
  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;

const itemSurchargesOf = (items: Item[]): number =>
  items.reduce((sum, item) => sum + cursedSurchargeOf(item), 0);

const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);

const quotePremium = (items: Item[]): number => {
  const policyBase = policyBaseOf(items);
  const rawPremium =
    policyBase + itemSurchargesOf(items) + firstInsuranceSurchargeOf(policyBase) + PROCESSING_FEE;
  return roundUpInMHPCOFavor(rawPremium);
};

export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
  return { results };
};

