import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Base premium calculations - quote operation
  it("quote with empty item list returns premium of 5 (just processing fee)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("quote with a single plain sword returns base premium + fee", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    // 100 base + 10 first insurance (10%) + 5 fee = 115
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote with a single plain amulet returns base premium + fee", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
        },
      ],
    });
    // 60 base + 6 first insurance (10%) + 5 fee = 71
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote with a single plain staff returns base premium + fee", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "staff", material: "oak", enchantment: 2, cursed: false }],
        },
      ],
    });
    // 80 base + 8 first insurance (10%) + 5 fee = 93
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("quote with a single plain potion returns base premium + fee", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }],
        },
      ],
    });
    // 40 base + 4 first insurance (10%) + 5 fee = 49
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // Components
  it("quote with 2 runes returns 50G base + fee (no block)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    // 50 base + 5 first insurance (10%) + 5 fee = 60
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("quote with 3 runes returns 60G base + fee (block applies)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    // 60 block base + 6 first insurance (10%) + 5 fee = 71
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("quote with 4 runes returns 100G base + fee (no block)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    // 100 base (no block) + 10 first insurance + 5 fee = 115
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("quote with 7 runes returns 175G base + fee", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    // 7*25 = 175 base (no block, requires exactly 3) + 17.5 first ins + 5 fee = 197.5 -> rounded up to 198
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });
  it("quote with 2 runes + 1 moonstone returns 75G base + fee (no block, different types)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    // 75 base (no block: different types) + 7.5 first ins + 5 fee = 87.5 -> 88
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("quote with 3 runes + 3 moonstones returns 120G base + fee (two separate blocks)", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    // 120 base (two blocks: 60+60) + 12 first ins + 5 fee = 137
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // Item-specific modifiers
  it("quote with a cursed sword adds 50% surcharge to sword base premium", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    // 100 base + 50 curse + 10 first insurance + 5 fee = 165
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("quote with a sword enchantment 5 adds 30% high-enchantment surcharge", () => {
    const result = processScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        },
      ],
    });
    // 100 base + 30 high-enchantment (30%) + 10 first insurance + 5 fee = 145
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("quote with a sword enchantment 4 does not add high-enchantment surcharge");
  it.todo("quote with a cursed sword enchantment 5 adds both surcharges");

  // Policy-wide modifiers
  it.todo("quote for customer with 2 years gets 20% loyalty discount on policy base");
  it.todo("quote applies 10% first insurance surcharge on policy base");
  it.todo("quote for customer's second contract applies 15% follow-up discount");

  // Multi-item policies - modifier scope
  it.todo("quote with cursed sword + plain amulet applies cursed surcharge only to sword");

  // Rounding
  it.todo("quote rounds final premium up (in MHPCO's favor)");

  // Integration examples
  it.todo("newcomer with cursed sword (steel, enchantment 3) -> premium 165");
  it.todo("long-standing customer's second contract with cursed sword enchantment 7 -> premium 160");

  // Claim processing - basic
  it.todo("claim with damage 500 on regular sword (no clauses) returns payout 400 (500 - 100 deductible)");
  it.todo("claim with damage 200 on a rune returns payout 100 (200 - 100 deductible)");

  // Claim - enchantment threshold
  it.todo("claim on enchantment 9 sword with damage 1000 returns payout 400 (50% then deductible)");

  // Claim - dragon material
  it.todo("claim on dragon-material sword damage 800 returns payout 700 (full then deductible)");

  // Claim - both clauses
  it.todo("claim on dragon-material enchantment 9 sword damage 1000 returns payout 400 (50% wins)");
  it.todo("claim on dragon-material enchantment 8 sword damage 1000 returns payout 400");

  // Claim - per-damage deductible
  it.todo("claim with two damaged items applies deductible per damage event");

  // Cap and remaining cap
  it.todo("claim returns remainingCap = cap - payout");
  it.todo("two successive claims exhaust the cap (1500/1500 on sword: 1400, then 600)");

  // CLI scenario with quote then claim
  it.todo("scenario with quote followed by claim returns results in order");
});

