const processClaim = (
  claimStep: ClaimStep,
  scenario: Scenario,
  priorPayout: number,
): ClaimResult => {
  const policyItems = originatingQuoteOf(claimStep, scenario).items;
  const cap = policyCapOf(policyItems);
  const desired = incidentPayoutOf(claimStep.incident, policyItems);
  const payout = Math.min(desired, cap - priorPayout);
  return { payout, remainingCap: cap - priorPayout - payout };
};

export const processScenario = (scenario: Scenario): { results: StepResult[] } => {
  const payoutsByPolicy = new Map<number, number>();
  const results: StepResult[] = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      return processQuote(step, scenario, index);
    }
    const prior = payoutsByPolicy.get(step.policy) ?? 0;
    const claimResult = processClaim(step, scenario, prior);
    payoutsByPolicy.set(step.policy, prior + claimResult.payout);
    return claimResult;
  });
  return { results };
};

